	@Test
	void coreExtractorConsumesOpaquePolicyAndFailsClosed() throws ReflectiveOperationException {
		SelectiveNameStatistics statistics = new SelectiveNameStatistics();
		JoinSearchService service = LmdbJoinSearchProvider.create(statistics, statistics);

		CoreExtraction safe = discover(service, extensionIsland());
		assertEquals(1, safe.results().size());
		MemoJoinRegionExtractor.Result safeResult = safe.results().getFirst();
		JoinRegion safeRegion = safeResult.region();
		int extensionGroupId = safe.rootExpression().inputs().get(0).groupId();
		int siblingGroupId = safe.rootExpression().inputs().get(1).groupId();
		int extensionOccurrenceId = occurrenceId(safeRegion, extensionGroupId);
		int siblingOccurrenceId = occurrenceId(safeRegion, siblingGroupId);
		MemoExpr extensionExpression = safe.memo()
				.group(extensionGroupId)
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Extension)
				.findFirst()
				.orElseThrow();

		StatementPattern follows = new StatementPattern(new Var("person"),
				Var.of("followsPred", FOLLOWS, false, true),
				new Var("x"));
		Extension bind = new Extension(follows, new ExtensionElem(new Str(new Var("x")), "xs"));
		StatementPattern consumesBindOutput = new StatementPattern(new Var("y"),
				Var.of("namePred", NAME, false, true),
				new Var("xs"));
		CoreExtraction unsafe = discover(service, new Join(bind, consumesBindOutput));

		Slice unknownComposite = new Slice(new StatementPattern(new Var("person"),
				Var.of("followsPred", FOLLOWS, false, true),
				new Var("x")), 0L, 1L);
		StatementPattern unknownSibling = new StatementPattern(new Var("x"),
				Var.of("namePred", NAME, false, true),
				new Var("nameValue"));
		CoreExtraction unknown = discover(service, new Join(unknownComposite, unknownSibling));

		assertAll(
				() -> assertTrue(safeResult.supported()),
				() -> assertEquals(Set.of(extensionGroupId, siblingGroupId), safeRegion.factors()
						.stream()
						.map(factor -> factor.groupId())
						.collect(Collectors.toUnmodifiableSet())),
				() -> assertTrue(safeRegion.requiredBefore(extensionOccurrenceId).isEmpty(),
						"A self-contained Extension must not depend on its later sibling"),
				() -> assertTrue(safeRegion.requiredBefore(siblingOccurrenceId).isEmpty(),
						"A disjoint sibling must be legal before the Extension"),
				() -> assertEquals(1, extensionExpression.inputGroupIds().size(),
						"An atomic join factor must retain its independently optimizable memo child"),
				() -> assertFailClosed(unsafe.results().getFirst(), "xs"),
				() -> assertFailClosed(unknown.results().getFirst(), "Slice"));
	}

	@Test
	void legacyGateIsRestoredWhenOpaqueFactorsAreDisabled() {
		String previous = System.getProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY);
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "false");
		try {
			assertFalse(LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(extensionIsland()),
					"Disabling opaque factors must restore the legacy written-order gate");
		} finally {
			if (previous == null) {
				System.clearProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY);
			} else {
				System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, previous);
			}
		}
	}

	@Test
	void extensionOutputSharedWithAnotherFactorKeepsIslandFrozen() {
		StatementPattern follows = new StatementPattern(new Var("person"),
				Var.of("followsPred", FOLLOWS, false, true),
				new Var("x"));
		Extension bind = new Extension(follows, new ExtensionElem(new Str(new Var("x")), "xs"));
		StatementPattern consumesBindOutput = new StatementPattern(new Var("y"),
				Var.of("namePred", NAME, false, true),
				new Var("xs"));
		assertFalse(LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(new Join(bind, consumesBindOutput)),
				"A BIND whose output is a runtime variable of another factor must not be reordered: written order "
						+ "joins on the shared name while a reordered Extension would overwrite it");
	}

	@Test
	void selectivePatternIsOrderedBeforeSelfContainedExtensionFactor() {
		TupleExpr island = extensionIsland();
		SelectiveNameStatistics statistics = new SelectiveNameStatistics();

		Optional<LmdbCascadesConnectedJoinPlanner.Plan> plan = LmdbCascadesConnectedJoinPlanner.plan(island, Set.of(),
				statistics, statistics);

		assertTrue(plan.isPresent(), "Expected the connected planner to own the BIND-bearing island");
		TupleExpr first = leftmostFactor(plan.get().tupleExpr());
		assertTrue(first instanceof StatementPattern,
				() -> "Expected the selective statement pattern to be seeded first: " + plan.get().tupleExpr());
		assertEquals(NAME, ((StatementPattern) first).getPredicateVar().getValue(),
				() -> "Expected the selective name lookup before the follows scan wrapped in BIND: "
						+ plan.get().tupleExpr());
	}

	@Test
	void volatileScalarFactorsKeepTheirWrittenOuterPlacement() {
		StatementPattern follows = new StatementPattern(new Var("person"),
				Var.of("followsPred", FOLLOWS, false, true),
				new Var("x"));
		Extension volatileBind = new Extension(follows, new ExtensionElem(new FunctionCall("UUID"), "token"));
		StatementPattern selectiveName = new StatementPattern(new Var("x"),
				Var.of("namePred", NAME, false, true),
				new Var("nameValue", VF.createLiteral("Name42")));
		Filter volatileFilter = new Filter(selectiveName.clone(), new FunctionCall("RAND"));

		assertTrue(descriptor(volatileBind).outerPlacementRestrictions()
				.stream()
				.anyMatch(barrier -> "VOLATILE_SCALAR".equals(barrier.name())),
				"A volatile BIND must carry an explicit outer-placement barrier");
		assertTrue(descriptor(volatileFilter).outerPlacementRestrictions()
				.stream()
				.anyMatch(barrier -> "VOLATILE_SCALAR".equals(barrier.name())),
				"A volatile FILTER must carry the same explicit barrier");

		SelectiveNameStatistics statistics = new SelectiveNameStatistics();
		Optional<LmdbCascadesConnectedJoinPlanner.Plan> plan = LmdbCascadesConnectedJoinPlanner
				.plan(new Join(volatileBind, selectiveName), Set.of(), statistics, statistics);

		assertTrue(plan.isPresent(), "The ordered volatile factor must not freeze unrelated join optimization");
		assertTrue(leftmostFactor(plan.get().tupleExpr()) instanceof Extension,
				() -> "The volatile BIND must remain before its selective sibling: " + plan.get().tupleExpr());
	}

