	void scalarEvaluationMultiplicityMakesVolatileJoinOrderObservable() {
		BindingSetAssignment rows = new BindingSetAssignment();
		rows.setBindingNames(Set.of("row"));
		MapBindingSet first = new MapBindingSet(1);
		first.addBinding("row", VF.createLiteral(1));
		MapBindingSet second = new MapBindingSet(1);
		second.addBinding("row", VF.createLiteral(2));
		MapBindingSet third = new MapBindingSet(1);
		third.addBinding("row", VF.createLiteral(3));
		rows.setBindingSets(List.of(first, second, third));

		assertVolatileExtensionMultiplicity(rows, new FunctionCall("UUID"), "uuid");
		assertVolatileExtensionMultiplicity(rows, new BNodeGenerator(), "bnode");

		Extension now = new Extension(new SingletonSet(), new ExtensionElem(new FunctionCall("NOW"), "now"));
		assertEquals(1, evaluate(new Join(now.clone(), rows.clone())).stream()
				.map(bindings -> bindings.getValue("now"))
				.collect(Collectors.toSet())
				.size());
		assertEquals(1, evaluate(new Join(rows.clone(), now)).stream()
				.map(bindings -> bindings.getValue("now"))
				.collect(Collectors.toSet())
				.size(), "NOW remains query-stable even when the right input is reopened");
	}

	@Test
	void volatileMinusRhsIsNotAdvertisedAsPrefixPushdown() {
		StatementPattern namedUser = new StatementPattern(new Var("user"),
				Var.of("namePred", NAME, false, true),
				new Var("name"));
		StatementPattern friend = new StatementPattern(new Var("user"),
				Var.of("followsPred", FOLLOWS, false, true),
				new Var("friend"));
		StatementPattern selfLoop = new StatementPattern(new Var("user"),
				Var.of("rhsFollowsPred", FOLLOWS, false, true),
				new Var("user"));
		Extension rhs = new Extension(selfLoop, new ExtensionElem(new FunctionCall("UUID"), "token"));

		assertFalse(LmdbJoinIslandConnectivity
				.minusJoinPrefixPushdownAvailable(new Difference(new Join(namedUser, friend), rhs)));
	}

	private static void assertVolatileExtensionMultiplicity(BindingSetAssignment rows, ValueExpr expression,
			String bindingName) {
		Extension extension = new Extension(new SingletonSet(), new ExtensionElem(expression, bindingName));
		assertEquals(1, evaluate(new Join(extension.clone(), rows.clone())).stream()
				.map(bindings -> bindings.getValue(bindingName))
				.collect(Collectors.toSet())
				.size());
		assertEquals(3, evaluate(new Join(rows.clone(), extension)).stream()
				.map(bindings -> bindings.getValue(bindingName))
				.collect(Collectors.toSet())
				.size(), "Reopening a volatile Extension once per left row changes its observable values");
	}

