	@Test
	void transparentNonScopeChangingProjectionRetainsExistingMobilityProof()
			throws ReflectiveOperationException {
		StatementPattern projectedRows = new StatementPattern(new Var("person"),
				Var.of("projectedPred", FOLLOWS, false, true), new Var("x"));
		Projection projection = new Projection(projectedRows,
				new ProjectionElemList(new ProjectionElem("person"), new ProjectionElem("x")), false);
		projection.setVariableScopeChange(false);
		StatementPattern names = new StatementPattern(new Var("x"),
				Var.of("namePred", NAME, false, true), new Var("name"));
		Join island = new Join(projection, names);
		SelectiveNameStatistics statistics = new SelectiveNameStatistics();
		CoreExtraction extraction = discover(LmdbJoinSearchProvider.create(statistics, statistics), island);
		int projectionGroupId = extraction.rootExpression().inputs().getFirst().groupId();
		int namesGroupId = extraction.rootExpression().inputs().get(1).groupId();
		MemoExpr projectionExpression = extraction.memo()
				.group(projectionGroupId)
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Projection)
				.findFirst()
				.orElseThrow();

		OpaqueFactorDescriptor descriptor = LmdbOpaqueJoinFactorPolicy.INSTANCE
				.classify(projectionExpression)
				.orElseThrow();
		MemoJoinRegionExtractor.Result result = extraction.results().getFirst();
		assertTrue(result.supported(), result.boundaries()::toString);
		JoinRegion region = result.region();
		int projectionOccurrenceId = occurrenceId(region, projectionGroupId);
		int namesOccurrenceId = occurrenceId(region, namesGroupId);

		assertAll(
				() -> assertTrue(LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(island)),
				() -> assertEquals(Set.of("PROJECTION"), descriptor.factorInternalBarriers()
						.stream()
						.map(Enum::name)
						.collect(Collectors.toUnmodifiableSet())),
				() -> assertTrue(descriptor.outerPlacementRestrictions().isEmpty(),
						"Only the established identity-projection proof may grant mobility"),
				() -> assertEquals(MemoJoinRegionExtractor.Status.EXTRACTED, result.status()),
				() -> assertEquals(2, region.factors().size()),
				() -> assertTrue(region.requiredBefore(projectionOccurrenceId).isEmpty()),
				() -> assertTrue(region.requiredBefore(namesOccurrenceId).isEmpty()),
				() -> assertEquals(1, projectionExpression.inputGroupIds().size()));
	}

