	@Test
	void coreExtractorPreservesServiceOccurrenceInputsAndWrittenBagSemantics()
			throws ReflectiveOperationException {
		BindingSetAssignment producer = assignment("x", "local-x");
		Service remote = serviceFactor();
		BindingSetAssignment consumer = assignment("remoteName", "x-bound");
		TupleExpr written = new Join(new Join(producer, remote), consumer);
		SelectiveNameStatistics statistics = new SelectiveNameStatistics();
		CoreExtraction extraction = discover(LmdbJoinSearchProvider.create(statistics, statistics), written);
		MemoJoinRegionExtractor.Result result = extraction.results().getFirst();
		assertTrue(result.supported(), result.boundaries()::toString);
		JoinRegion region = result.region();
		MemoExpr leftJoin = extraction.memo()
				.group(extraction.rootExpression().inputs().getFirst().groupId())
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Join)
				.findFirst()
				.orElseThrow();
		int producerGroupId = leftJoin.inputs().get(0).groupId();
		int serviceGroupId = leftJoin.inputs().get(1).groupId();
		int consumerGroupId = extraction.rootExpression().inputs().get(1).groupId();
		int producerOccurrenceId = occurrenceId(region, producerGroupId);
		int serviceOccurrenceId = occurrenceId(region, serviceGroupId);
		int consumerOccurrenceId = occurrenceId(region, consumerGroupId);
		MemoExpr serviceExpression = extraction.memo()
				.group(serviceGroupId)
				.expressions()
				.stream()
				.filter(MemoExpr::logical)
				.filter(expression -> expression.tupleExpr() instanceof Service)
				.findFirst()
				.orElseThrow();
		OpaqueFactorDescriptor descriptor = LmdbOpaqueJoinFactorPolicy.INSTANCE
				.classify(serviceExpression)
				.orElseThrow();
		JoinTree producerTree = JoinTree.factor(producerOccurrenceId);
		JoinTree serviceTree = JoinTree.factor(serviceOccurrenceId);
		JoinTree consumerTree = JoinTree.factor(consumerOccurrenceId);
		FederatedServiceResolver resolver = ignored -> new BindingAwareFederatedService();
		List<BindingSet> writtenRows = evaluate(written.clone(), resolver);
		List<BindingSet> illegalRows = evaluate(
				new Join(new Join(remote.clone(), producer.clone()), consumer.clone()), resolver);

		assertAll(
				() -> assertTrue(result.supported(), result.boundaries()::toString),
				() -> assertEquals(Set.of("x"),
						extraction.memo().universe().names(region.requiredInputBindings(serviceOccurrenceId)),
						"Only a SERVICE input assured before this occurrence is an effective requirement"),
				() -> assertEquals(Set.of(producerOccurrenceId), region.requiredBefore(serviceOccurrenceId)),
				() -> assertEquals(Set.of(serviceOccurrenceId), region.requiredBefore(consumerOccurrenceId)),
				() -> assertEquals(1, serviceExpression.inputGroupIds().size(),
						"The opaque SERVICE must retain its independently optimizable child"),
				() -> assertEquals(Set.of(OpaqueFactorDescriptor.SemanticBarrier.SERVICE),
						descriptor.factorInternalBarriers()),
				() -> assertEquals(Set.of(OpaqueFactorDescriptor.SemanticBarrier.SERVICE),
						descriptor.outerPlacementRestrictions()),
				() -> assertTrue(region.isLegal(JoinTree.join(JoinTree.join(producerTree, serviceTree), consumerTree))),
				() -> assertTrue(region.isLegal(JoinTree.join(producerTree, JoinTree.join(serviceTree, consumerTree)))),
				() -> assertFalse(
						region.isLegal(JoinTree.join(JoinTree.join(serviceTree, producerTree), consumerTree))),
				() -> assertFalse(
						region.isLegal(JoinTree.join(JoinTree.join(producerTree, consumerTree), serviceTree))),
				() -> assertEquals(1, writtenRows.size()),
				() -> assertEquals(VF.createLiteral("x-bound"), writtenRows.getFirst().getValue("remoteName")),
				() -> assertTrue(illegalRows.isEmpty(),
						"Moving SERVICE before its local input changes the remote result bag"));
	}

